import React, { useState } from "react";
import EmailPreviewModal from "../../components/admin/EmailPreviewModal";

const templates = [
  { id: "valentine", name: "💘 Valentine" },
  { id: "women", name: "🌸 8/3 Quốc tế Phụ Nữ" },
  { id: "teacher", name: "📚 20/11 Ngày Nhà Giáo" },
  { id: "noel", name: "🎄 Giáng Sinh" },
  { id: "tet", name: "🧧 Tết Nguyên Đán" },
];

const SendEmailPage = () => {
  const [selectedTemplate, setSelectedTemplate] = useState("");
  const [group, setGroup] = useState("all");
  const [previewOpen, setPreviewOpen] = useState(false);
  const [result, setResult] = useState("");
  const token = JSON.parse(localStorage.getItem("userInfo"))?.token;

  const sendEmail = async () => {
    if (!selectedTemplate) return alert("Chọn template trước!");
    setResult("Đang gửi...");
    
    const res = await fetch("http://localhost:5000/api/email/send", {
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        event: selectedTemplate,
        group,
      }),
    });

    const data = await res.json();
    setResult(data.success ? "📨 Đã gửi thành công!" : "❌ Lỗi khi gửi!");
  };

  return (
    <div className="p-8 max-w-3xl mx-auto">

      <h2 className="text-2xl font-bold text-[#e06c7f] mb-4">📤 Gửi Email Marketing</h2>

      {/* Select template */}
      <label className="block font-medium mb-2">Chọn dịp email</label>
      <select
        className="w-full border p-3 rounded-lg mb-4"
        value={selectedTemplate}
        onChange={(e) => setSelectedTemplate(e.target.value)}
      >
        <option value="">-- Chọn mẫu email --</option>
        {templates.map((t) => (
          <option key={t.id} value={t.id}>{t.name}</option>
        ))}
      </select>

      {/* Select group */}
      <label className="block font-medium mb-2">Gửi tới</label>
      <select
        className="w-full border p-3 rounded-lg mb-4"
        value={group}
        onChange={(e) => setGroup(e.target.value)}
      >
        <option value="all">Tất cả người dùng</option>
        <option value="subscribers">Người đăng ký newsletter</option>
        <option value="customers">Khách từng mua hàng</option>
      </select>

      <div className="flex gap-4">
        <button
          onClick={() => setPreviewOpen(true)}
          className="px-4 py-3 bg-gray-200 rounded-lg"
        >
          👀 Xem trước
        </button>

        <button
          onClick={sendEmail}
          className="px-5 py-3 bg-[#e06c7f] text-white rounded-lg hover:bg-[#d0536d]"
        >
          🚀 Gửi Email
        </button>
      </div>

      {result && <p className="mt-4 text-lg font-medium">{result}</p>}

      {/* Modal Preview */}
      {previewOpen && (
        <EmailPreviewModal
          template={selectedTemplate}
          onClose={() => setPreviewOpen(false)}
        />
      )}
    </div>
  );
};

export default SendEmailPage;
